/bin/zsh -lc "python -c \"import pandas as pd, numpy as np; from sklearn.model_selection import KFold, cross_val_score; from sklearn.linear_model import LinearRegression; from sklearn.pipeline import make_pipeline; from sklearn.preprocessing import PolynomialFeatures; df=pd.read_csv('dataset.csv'); y=df['monthly_rent_usd']; cv=KFold(n_splits=5, shuffle=True, random_state=42); X1=df[['sq_ft','bedrooms','bathrooms','distance_to_center_km','year_built','has_parking','pet_friendly']]; X2=X1[['sq_ft','bedrooms','bathrooms']]; models={'linear_all':(X1,LinearRegression()), 'poly2_core':(X2,make_pipeline(PolynomialFeatures(degree=2, include_bias=False), LinearRegression()))};
for name,(X,m) in models.items():
 r2=cross_val_score(m,X,y,cv=cv,scoring='r2'); rmse=np.sqrt(-cross_val_score(m,X,y,cv=cv,scoring='neg_mean_squared_error')); print(name, 'r2_mean', r2.mean(), 'rmse_mean', rmse.mean())\""

